    @csrf <input id="crud-method" type="hidden" name="_method" value="">
    <header class="employee-crud-header"><div><span id="crud-title" class="employee-crud-kicker">Nuevo empleado</span><h3>Ficha del colaborador</h3><p>Administra la ficha y la KEY para vincular la aplicación cliente.</p></div><button id="crud-close" type="button" aria-label="Cerrar modal" class="employee-crud-close">×</button></header>
    <div class="employee-crud-fields">
      <label>ID interno<input id="crud-id" readonly></label>
      <label>Estado<select id="crud-status" name="status"><option value="offline">Offline</option><option value="online">Online (Disponible)</option><option value="active">Activo (Live)</option><option value="idle">Inactivo (Idle)</option><option value="locked">Bloqueado</option></select></label>
      <label class="employee-crud-wide">Nombre completo<input id="crud-name" name="name" required placeholder="Ej. Juan Pérez"></label>
      <label>Departamento / área<select id="crud-department" name="department"><option>Desarrollo de Software</option><option>Ventas y Clientes</option><option>Marketing Digital</option><option>Soporte Técnico</option><option>Talento Humano</option><option value="__other">Otro / escribir área…</option></select><input id="crud-department-custom" class="hidden" placeholder="Escribe el departamento o área"></label>
      <label>País<select id="crud-country" name="country"><option>México</option><option>Colombia</option><option>Estados Unidos</option><option>Brasil</option><option>España</option><option>Argentina</option><option>Chile</option><option>Perú</option></select></label>
