    <footer class="employee-crud-actions">@if($isAdmin)<button id="crud-delete" type="button" class="employee-crud-delete hidden">Eliminar empleado</button>@endif<button id="crud-cancel" type="button">Cancelar</button><button id="crud-submit">Crear empleado</button></footer>
  </form>
